uint p = thread_position_in_grid.x;
int pixelCount = int(counts_1[0]);
if (int(p) >= pixelCount) {
    return;
}
int gaussianCount = int(counts_1[1]);
bool whiteBg = counts_1[2] != 0;

float px = tileCoord_1[p * 2 + 0];
float py = tileCoord_1[p * 2 + 1];

float T = 1.0f;
float accAlpha = 0.0f;
float accumColorX = 0.0f;
float accumColorY = 0.0f;
float accumColorZ = 0.0f;
float accumDepth = 0.0f;

for (int i = 0; i < gaussianCount; ++i) {
    float dx = px - sortedMeans2d_1[i * 2 + 0];
    float dy = py - sortedMeans2d_1[i * 2 + 1];
    uint conicBase = uint(i) * 4;
    float exponent = -0.5f * (
        dx * dx * sortedConic_1[conicBase + 0] +
        dy * dy * sortedConic_1[conicBase + 3] +
        dx * dy * sortedConic_1[conicBase + 1] +
        dx * dy * sortedConic_1[conicBase + 2]
    );
    float alpha = exp(exponent) * sortedOpacity_1[i];
    if (alpha > 0.99f) {
        alpha = 0.99f;
    }

    float contrib = T * alpha;
    accAlpha += contrib;
    uint colorBase = uint(i) * 3;
    accumColorX += contrib * sortedColor_1[colorBase + 0];
    accumColorY += contrib * sortedColor_1[colorBase + 1];
    accumColorZ += contrib * sortedColor_1[colorBase + 2];
    accumDepth += contrib * sortedDepths_1[i];
    T *= (1.0f - alpha);

    if (T < 1e-4f) {
        break;
    }
}

float bg = whiteBg ? (1.0f - accAlpha) : 0.0f;
outColor_1[p * 3 + 0] = accumColorX + bg;
outColor_1[p * 3 + 1] = accumColorY + bg;
outColor_1[p * 3 + 2] = accumColorZ + bg;
outDepth_1[p] = accumDepth;
outAlpha_1[p] = accAlpha;
